function calculateScores(answers) {
    let S = 0;
    let L = 0;
    let D = 0;
    let W = 0;
    for(let i = 0; i < answers.length; i++){
        const dimension = questionDimensions[i];
        const score = answers[i];
        switch(dimension){
            case 'S':
                S += score;
                break;
            case 'L':
                L += score;
                break;
            case 'D':
                D += score;
                break;
            case 'W':
                W += score;
                break;
        }
    }
    return {
        S,
        L,
        D,
        W
    };
}
function determineDirection(score, maxPossibleScore) {
    const threshold = maxPossibleScore * 0.5;
    return score > threshold ? 'positive' : 'negative';
}
function matchPersonality(scores, maxPossibleScores) {
    const dimensionDirections = {
        S: determineDirection(scores.S, maxPossibleScores.S),
        L: determineDirection(scores.L, maxPossibleScores.L),
        D: determineDirection(scores.D, maxPossibleScores.D),
        W: determineDirection(scores.W, maxPossibleScores.W)
    };
    const matchedPersonalities = (0, _personalities.personalities).filter((personality)=>{
        return personality.dimensions.S === dimensionDirections.S && personality.dimensions.L === dimensionDirections.L && personality.dimensions.D === dimensionDirections.D && personality.dimensions.W === dimensionDirections.W && !personality.isEasterEgg;
    });
    if (matchedPersonalities.length > 0) return matchedPersonalities[0];
    const easterEggPersonalities = (0, _personalities.personalities).filter((personality)=>{
        return personality.dimensions.S === dimensionDirections.S && personality.dimensions.L === dimensionDirections.L && personality.dimensions.D === dimensionDirections.D && personality.dimensions.W === dimensionDirections.W && personality.isEasterEgg;
    });
    if (easterEggPersonalities.length > 0) return easterEggPersonalities[0];
    return (0, _personalities.personalities)[0];
}
function getDimensionQuestionCounts() {
    const counts = {
        S: 0,
        L: 0,
        D: 0,
        W: 0
    };
    questionDimensions.forEach((dimension)=>{
        counts[dimension]++;
    });
    return counts;
}
function getMaxPossibleScores() {
    const counts = getDimensionQuestionCounts();
    return {
        S: counts.S,
        L: counts.L,
        D: counts.D,
        W: counts.W
    };
}
function generateTestResult(answers) {
    const scores = calculateScores(answers);
    const maxPossibleScores = getMaxPossibleScores();
    const personality = matchPersonality(scores, maxPossibleScores);
    const dimensionResults = {
        S: {
            direction: determineDirection(scores.S, maxPossibleScores.S),
            score: scores.S
        },
        L: {
            direction: determineDirection(scores.L, maxPossibleScores.L),
            score: scores.L
        },
        D: {
            direction: determineDirection(scores.D, maxPossibleScores.D),
            score: scores.D
        },
        W: {
            direction: determineDirection(scores.W, maxPossibleScores.W),
            score: scores.W
        }
    };
    return {
        scores,
        personality,
        dimensionResults
    };
}

